9→
10→  const handleSubmit = async (e) => {
11→    e.preventDefault();
12→    try {
13→      const response = await axios.post(`http://${window.location.hostname}:8000/token`, 
14→        new URLSearchParams({ username, password }),
15→        { headers: { 'Content-Type': 'application/x-www-form-urlencoded' } }
16→      );
17→      const token = response.data.access_token;
18→      localStorage.setItem('token', token);
19→      
20→      // Get full user data from /me endpoint
21→      const userResponse = await axios.get(`http://${window.location.hostname}:8000/users/me`, {
22→        headers: { Authorization: `Bearer ${token}` }
23→      });
